cssImplementation:
.under-link { position:relative; }
.under-link::after {
  content:''; position:absolute; left:0; right:0; bottom:0;
  height: var(--ut, 2px); background: var(--uc, gold);
  transform: scaleX(0); transform-origin: left;
  transition: transform var(--ud, 600ms) cubic-bezier(.7,0,.3,1);
}
.under-link:hover::after, .under-link.cycle::after { transform: scaleX(1); }
